import { useState, useEffect, useRef } from "react";

export default function App() {
  return (
    <div style={{
      background:"#020b18", minHeight:"100vh",
      display:"flex", alignItems:"center", justifyContent:"center",
      fontFamily:"monospace"
    }}>
      <div style={{textAlign:"center"}}>
        <h1 style={{color:"#f0b429", fontSize:"3rem"}}>HydroMind AI ⚙️</h1>
        <p style={{color:"#1a9fd4", fontSize:"1.2rem"}}>
          Hydraulic AI Advisor — Design. Diagnose. Solve.
        </p>
        <p style={{color:"#6b8fa8", marginTop:"1rem"}}>
          ✅ React app working correctly
        </p>
      </div>
    </div>
  );
}
